#!/bin/bash
set -e
mkdir -p /opt/probe
cat > /tmp/FailoverProbe.b64 <<'B64EOF'

B64EOF
base64 -d /tmp/FailoverProbe.b64 > /opt/probe/FailoverProbe.java
CP=$(echo /opt/rocketmq-4.9.7/lib/*.jar | tr ' ' ':')
cd /opt/probe
javac -cp "$CP" FailoverProbe.java && echo "COMPILE_OK" || echo "COMPILE_FAIL"
ls /opt/probe/*.class 2>/dev/null | head
